// tests/fixtures/_generators/hash-passwords.js
// @ts-check
// Phase 2 (D-12): One-shot Node script generating SHA-256 hex for known-password
// fixtures. Run via: node tests/fixtures/_generators/hash-passwords.js
// Output is committed to tests/fixtures/auth-passwords.js.
//
// Excluded from coverage by vite.config.js (coverage.exclude includes
// **/_generators/** -- added in Plan 02-06).

import { createHash } from "node:crypto";
import { writeFileSync } from "node:fs";
import { fileURLToPath } from "node:url";
import { dirname, join } from "node:path";

const passwords = {
  internal: "TestInternal!2026",
  orgClient: "TestOrgClient!2026",
  user: "TestUser!2026",
};

const entries = Object.entries(passwords).map(([label, plain]) => {
  const sha256 = createHash("sha256").update(plain, "utf8").digest("hex");
  return `  ${label}: { plain: ${JSON.stringify(plain)}, sha256: ${JSON.stringify(sha256)} },`;
});

const out = `// tests/fixtures/auth-passwords.js
// @ts-check
// Phase 2 (D-12): GENERATED by tests/fixtures/_generators/hash-passwords.js.
// DO NOT edit by hand -- re-run the generator if you need to change inputs.
// These are TEST passwords only; they exist solely to drive the auth state-machine
// regression baseline (TEST-07) and are excluded from production paths by
// ESLint no-restricted-imports (rule added in Plan 02-06 if not already in Phase 1).

export const knownPasswords = {
${entries.join("\n")}
};
`;

const here = dirname(fileURLToPath(import.meta.url));
const outPath = join(here, "..", "auth-passwords.js");
writeFileSync(outPath, out, "utf8");
console.log(`Wrote ${outPath}`);
